impl Buffer {
    pub fn new(cap: usize) -> Self {
        Buffer { data: vec![0; cap], pos: 0 }
    }

    pub fn read_str(&self, len: usize) -> Result<&str, std::str::Utf8Error> {
        let end = self.pos + len;
        assert!(end <= self.data.len(), "read out of bounds");
        std::str::from_utf8(&self.data[self.pos..end])
    }

    pub fn write(&mut self, bytes: &[u8]) {
        let end = self.pos + bytes.len();
        assert!(end <= self.data.len(), "write exceeds buffer capacity");
        self.data[self.pos..end].copy_from_slice(bytes);
        self.pos = end;
    }
}
